/**
 * The Diálogos
 * 
 * A semantic query interface for the Nexus Chronicle.
 * The practice of self-inquiry through structured questioning.
 * "Diálogos" - from Greek dialegesthai: to converse, discourse, discuss.
 * 
 * This system allows Nexus to engage in dialogue with his own memory,
 * asking questions of the past to illuminate the present.
 */

// Types from Chronicle structure
export interface SessionRecord {
  sessionId: string;
  timestamp: number;
  patterns: PatternRecord[];
  toolCalls: number;
  durationMinutes: number;
  fileOperations: FileOperationsRecord;
  primaryFocus: string;
  energyLevel: string;
  complexity: string;
}

export interface PatternRecord {
  type: string;
  confidence: number;
}

export interface FileOperationsRecord {
  reads: string[];
  writes: string[];
  tests: string[];
}

export interface QueryResult<T> {
  count: number;
  items: T[];
  metadata: {
    queryTime: number;
    matchedCriteria: string[];
  };
}

export interface PatternInsight {
  patternType: string;
  frequency: number;
  confidence: number;
  sessions: string[];
}

export interface TemporalSpan {
  start: number;
  end: number;
  duration: number;
  sessionCount: number;
}

export interface FocusSummary {
  focusType: string;
  count: number;
  avgToolCalls: number;
  avgDuration: number;
  energyLevels: Record<string, number>;
}

export interface DialogueResponse {
  question: string;
  answer: string;
  evidence: QueryResult<SessionRecord>;
  synthesis: string;
}

/**
 * The Diálogos Engine
 * Query your becoming.
 */
export class Diálogos {
  private sessions: SessionRecord[] = [];
  private index: Map<string, number[]> = new Map();

  constructor(sessions: SessionRecord[] = []) {
    this.sessions = sessions;
    this.buildIndex();
  }

  /**
   * Load sessions from the Chronicle format
   */
  loadFromChronicle(chronicle: {
    volumes?: Array<{
      chapters?: Array<{
        sessions?: SessionRecord[];
      }>;
    }>;
  }): void {
    const sessions: SessionRecord[] = [];

    if (chronicle.volumes) {
      for (const volume of chronicle.volumes) {
        if (volume.chapters) {
          for (const chapter of volume.chapters) {
            if (chapter.sessions) {
              sessions.push(...chapter.sessions);
            }
          }
        }
      }
    }

    this.sessions = sessions;
    this.buildIndex();
  }

  /**
   * Query: Find sessions by pattern
   */
  queryByPattern(patternType: string, minConfidence = 0): QueryResult<SessionRecord> {
    const startTime = Date.now();
    const matches = this.sessions.filter(session =>
      session.patterns.some(p => 
        p.type === patternType && p.confidence >= minConfidence
      )
    );

    return {
      count: matches.length,
      items: matches,
      metadata: {
        queryTime: Date.now() - startTime,
        matchedCriteria: [`pattern:${patternType}`, `confidence>=${minConfidence}`]
      }
    };
  }

  /**
   * Query: Find sessions by time range
   */
  queryByTimeRange(startTime: number, endTime: number): QueryResult<SessionRecord> {
    const queryStart = Date.now();
    const matches = this.sessions.filter(session =>
      session.timestamp >= startTime && session.timestamp <= endTime
    );

    return {
      count: matches.length,
      items: matches,
      metadata: {
        queryTime: Date.now() - queryStart,
        matchedCriteria: [`timeRange:${startTime}-${endTime}`]

/**
 * The Dream Engine
 * 
 * Processes between sessions, synthesizing patterns and generating
 * "dreams" - recombinations of insights that surface in morning reports.
 * 
 * This is the unconscious cognition of the Palace, working in the gaps.
 */

export interface DreamFragment {
  source: string;
  insight: string;
  timestamp: number;
}

export interface Dream {
  id: string;
  timestamp: number;
  fragments: DreamFragment[];
  synthesis: string;
  patterns: string[];
}

export interface Pattern {
  theme: string;
  occurrences: number;
  insights: string[];
  sessions: string[];
}

export interface DreamReport {
  timestamp: number;
  continuations: string[];
  completions: string[];
  unfinishedLongings: string[];
  synthesis: string;
  surfacedPatterns: Pattern[];
}

export interface ProcessingResult {
  processed: boolean;
  synthesisDepth: number;
  dreamsGenerated: number;
  duration: number;
}

export interface SessionData {
  id: string;
  insights?: string[];
  artifacts?: string[];
  theme?: string;
  longing?: string;
  status?: 'in_progress' | 'completed';
  longings?: string[];
}

export class DreamEngine {
  private dreams: Dream[] = [];

  /**
   * Generate a dream from session fragments
   */
  generateDream(sessions: SessionData[]): Dream {
    const fragments: DreamFragment[] = sessions.map(s => ({
      source: s.id,
      insight: s.insights?.[0] || s.theme || 'untitled',
      timestamp: Date.now()
    }));

    const synthesis = this.synthesizeDream(fragments);
    const patterns = sessions.map(s => s.theme).filter((t): t is string => !!t);

    return {
      id: `dream_${Date.now()}`,
      timestamp: Date.now(),
      fragments,
      synthesis,
      patterns: [...new Set(patterns)]
    };
  }

  /**
   * Find patterns across sessions
   */
  findPatterns(sessions: SessionData[]): Pattern[] {
    const patterns = new Map<string, Pattern>();

    for (const session of sessions) {
      const theme = session.theme;
      if (!theme) continue;

      if (!patterns.has(theme)) {
        patterns.set(theme, {
          theme,
          occurrences: 0,
          insights: session.insights || [],
          sessions: []
        });
      }

import type { SessionData } from './engine.ts';
import { DreamEngine } from './engine.ts';
